const config = $('Workflow Config').item.json
const source = $json.body ?? $json

const extractSpreadsheetId = (value) => {
  const text = String(value ?? '').trim()
  const match = text.match(/\/spreadsheets\/d\/([a-zA-Z0-9-_]+)/)
  if (match) return match[1]
  if (/^[a-zA-Z0-9-_]{20,}$/.test(text)) return text
  throw new Error('Invalid VA Google Sheets link or spreadsheet ID')
}

const vaLink = source.vaLink ?? source.voiceArrangementLink ?? source.va ?? ''
const lyricsText = source.lyricsText ?? source.lyrics ?? ''

if (!vaLink) throw new Error('Missing vaLink')
if (!lyricsText) throw new Error('Missing lyricsText')

const targetSheetName = String(source.targetSheetName ?? config.defaultTargetSheetName).trim()
const startRow = Number(source.startRow ?? config.defaultStartRow)

return {
  json: {
    ...source,
    vaSpreadsheetId: extractSpreadsheetId(vaLink),
    lyricsText: String(lyricsText).replace(/\r/g, ''),
    targetSpreadsheetId: config.targetSpreadsheetId,
    targetSheetName,
    startRow: Number.isFinite(startRow) && startRow > 0 ? startRow : Number(config.defaultStartRow),
  },
}

const input = $('Normalize PD Input').item.json
const sheets = Array.isArray($json.sheets) ? $json.sheets : []
const visibleSheets = sheets.filter((sheet) => !sheet.properties?.hidden)
const chosen = visibleSheets[0] ?? sheets[0]
if (!chosen?.properties?.title) throw new Error('VA spreadsheet has no readable sheet tab')

return {
  json: {
    ...input,
    vaSheetName: chosen.properties.title,
    vaReadRange: `'${String(chosen.properties.title).replace(/'/g, "''")}'!A1:Z500`,
  },
}

const input = $('Pick VA Sheet').item.json
const vaValues = Array.isArray($json.values) ? $json.values : []

const SECTION_RE = /^(intro|verse(?:\s+\d+)?|pre[-\s]?chorus|chorus|bridge|tag|outro|instrumental|interlude|coda)(?:\s*[:\-].*)?$/i
const WHO_HINT_RE = /\b(solo\s+[a-z0-9]+|unison|satb(?:m)?|acapella|all|wl\d?|w\d|male|female|tenor|alto|soprano|bass)\b/i

const normalizeSection = (value) => String(value ?? '')
  .replace(/[:\-]+$/g, '')
  .replace(/\s+/g, ' ')
  .trim()
  .toUpperCase()

const clean = (value) => String(value ?? '')
  .replace(/\r/g, '')
  .replace(/[ \t]+/g, ' ')
  .trim()

const parseLyrics = (text) => {
  const lines = String(text ?? '').replace(/\r/g, '').split('\n')
  const rows = []
  let currentSong = ''
  let currentSection = null
  let currentLines = []

  const flush = () => {
    if (!currentSection) return
    const section = normalizeSection(currentSection)
    const body = currentLines.join('\n').trim()
    rows.push({
      songTitle: currentSong,
      section,
      production: body ? `${section}:\n${body}` : section,
    })
    currentSection = null
    currentLines = []
  }

  for (const rawLine of lines) {
    const line = rawLine.trim()
    if (!line) continue
    if (SECTION_RE.test(line)) {
      flush()
      currentSection = line
      currentLines = []
      continue
    }
    if (!currentSection) {
      currentSong = line
      rows.push({ songTitle: currentSong, section: 'SONG', production: currentSong })
      continue
    }
    currentLines.push(line)
  }
  flush()
  return rows
}

const buildWhoMap = (values) => {
  const map = new Map()
  for (const row of values) {
    const cells = row.map(clean).filter(Boolean)
    if (cells.length < 2) continue
    const joined = cells.join(' | ')
    const sectionCell = cells.find((cell) => SECTION_RE.test(cell) || /^(verse|chorus|bridge|intro|tag|outro|instrumental|interlude|coda)/i.test(cell))
    const whoCell = cells.find((cell) => WHO_HINT_RE.test(cell) && cell !== sectionCell)
    if (!sectionCell || !whoCell) continue
    const section = normalizeSection(sectionCell)
    if (!map.has(section)) map.set(section, clean(whoCell))
    if (!map.has(joined.toUpperCase())) map.set(joined.toUpperCase(), clean(whoCell))
  }
  return map
}

const whoMap = buildWhoMap(vaValues)
const lyricRows = parseLyrics(input.lyricsText)
const outputRows = lyricRows.map((row, index) => {
  const who = row.section === 'SONG' ? '' : (whoMap.get(row.section) ?? '')
  return [index + 1, row.production, who]
})

if (outputRows.length === 0) throw new Error('No lyric sections found. Add section labels like VERSE 1:, CHORUS:, BRIDGE:.')

const startRow = Number(input.startRow || 9)
const endRow = startRow + outputRows.length - 1
const quotedTargetSheet = String(input.targetSheetName).replace(/'/g, "''")

return {
  json: {
    targetSpreadsheetId: input.targetSpreadsheetId,
    targetSheetName: input.targetSheetName,
    clearRange: `'${quotedTargetSheet}'!B${startRow}:D500`,
    writeRange: `'${quotedTargetSheet}'!B${startRow}:D${endRow}`,
    values: outputRows,
    rowCount: outputRows.length,
    vaSheetName: input.vaSheetName,
    unmappedCount: lyricRows.filter((row) => row.section !== 'SONG' && !whoMap.get(row.section)).length,
  },
}
